public boolean canReach(int targetX, int targetY) {
    while (targetX > 1 && targetY > 1) {
        if(targetX < targetY) {
            int temp = targetX;
            targetX = targetY;
            targetY = temp;
        }
        targetX -= targetY;
    }
    return targetX == 1 || targetY == 1;
}
